    def Dialog_Select(self, title, items):
        win = xbmcgui.Window(10000)
        
        # AUTO-SELECT: Try to match episode from MRSP context
        auto_index = self._try_auto_select_episode(items)
        if auto_index >= 0:
            log.info("BufferingDialog: Auto-selected index %d: %s" % (auto_index, str(items[auto_index])[:60]))
            return auto_index
        
        # Manual selection
        win.setProperty('elem.buf.selecting', 'true')
        self._close_buffering_for_selection()
        
        dialog = xbmcgui.Dialog()
        result = dialog.select(getLocalizedLabel(title), items)
        
        win.clearProperty('elem.buf.selecting')
        self._reset_buffering_launch()
        return result

    def _try_auto_select_episode(self, items):
        """Auto-select episode from season pack"""
        if not items or len(items) <= 1:
            return -1
        
        win = xbmcgui.Window(10000)
        season = None
        episode = None
        
        # SOURCE 1 (PRIORITAR): Properties dedicate de la MRSP
        s = win.getProperty('mrsp.elem.autoselect.season')
        e = win.getProperty('mrsp.elem.autoselect.episode')
        if s and e:
            try:
                season = int(str(s).lstrip('0') or '0')
                episode = int(str(e).lstrip('0') or '0')
                log.info("BufferingDialog: Got S%02dE%02d from autoselect properties" % (season, episode))
            except:
                pass
        
        # SOURCE 2: mrsp.data (poate fi stale, dar încercăm)
        if season is None or episode is None:
            mrsp_data_str = win.getProperty('mrsp.data')
            if mrsp_data_str:
                try:
                    try:
                        mrsp_data = ast.literal_eval(mrsp_data_str)
                    except:
                        mrsp_data = {}
                    
                    # Try mrsp_resume_id first (most reliable)
                    resume_id = mrsp_data.get('mrsp_resume_id', '')
                    m = re.search(r'S(\d+)E(\d+)', resume_id, re.IGNORECASE)
                    if m:
                        season = int(m.group(1))
                        episode = int(m.group(2))
                        log.info("BufferingDialog: Got S%02dE%02d from mrsp_resume_id" % (season, episode))
                    
                    if season is None or episode is None:
                        s_val = mrsp_data.get('season') or mrsp_data.get('Season')
                        e_val = mrsp_data.get('episode') or mrsp_data.get('Episode')
                        if s_val is None or e_val is None:
                            info = mrsp_data.get('info', {})
                            if s_val is None:
                                s_val = info.get('season') or info.get('Season')
                            if e_val is None:
                                e_val = info.get('episode') or info.get('Episode')
                        if s_val is not None:
                            season = int(str(s_val).lstrip('0') or '0')
                        if e_val is not None:
                            episode = int(str(e_val).lstrip('0') or '0')
                except:
                    pass
        
        # SOURCE 3: Kodi InfoLabels
        if season is None:
            s = xbmc.getInfoLabel('ListItem.Season')
            if s:
                try: season = int(s)
                except: pass
        if episode is None:
            e = xbmc.getInfoLabel('ListItem.Episode')
            if e:
                try: episode = int(e)
                except: pass
        
        # SOURCE 4: VideoPlayer
        if season is None:
            s = xbmc.getInfoLabel('VideoPlayer.Season')
            if s:
                try: season = int(s)
                except: pass
        if episode is None:
            e = xbmc.getInfoLabel('VideoPlayer.Episode')
            if e:
                try: episode = int(e)
                except: pass
        
        log.info("BufferingDialog: Auto-select: season=%s, episode=%s, items=%d" % (season, episode, len(items)))
        
        if season is None or episode is None or episode == 0:
            return -1
        
        # Patterns
        patterns = [
            r'S%02dE%02d' % (season, episode),
            r'[Ss]%02d[Ee]%02d' % (season, episode),
            r'S%dE%d\b' % (season, episode),
            r'%dx%02d' % (season, episode),
            r'[Ee]%02d[^0-9]' % episode,
        ]
        
        for pattern in patterns:
            for i, item in enumerate(items):
                if re.search(pattern, str(item), re.IGNORECASE):
                    log.info("BufferingDialog: MATCH '%s' at index %d" % (str(item)[:60], i))
                    # Curățăm autoselect properties după utilizare
                    win.clearProperty('mrsp.elem.autoselect.season')
                    win.clearProperty('mrsp.elem.autoselect.episode')
                    return i
        
        log.info("BufferingDialog: No match for S%02dE%02d" % (season, episode))
        return -1

